// SAMPLE dealer inventory — clearly illustrative.
// In production this node is replaced by a Supabase/Postgres read of the
// AlbaScope Inventory `cars` table (Assignment 2). The rest of the workflow
// is identical either way.
const inventory = [
  { stockId: 'ALB-001', vin: '4T1BF1FK5CU513331', make: 'Toyota',    model: 'Camry',           year: 2012 },
  { stockId: 'ALB-002', vin: '1HGCR2F30DA000000', make: 'Honda',     model: 'Accord',          year: 2013 },
  { stockId: 'ALB-003', vin: '1FMCU0GX7DUA00000', make: 'Ford',      model: 'Escape',          year: 2013 },
  { stockId: 'ALB-004', vin: '1N4AL3AP0DC000000', make: 'Nissan',    model: 'Altima',          year: 2013 },
  { stockId: 'ALB-005', vin: '5XXGM4A70DG000000', make: 'Kia',       model: 'Optima',          year: 2013 },
  { stockId: 'ALB-006', vin: '5NPE24AF5FH000000', make: 'Hyundai',   model: 'Sonata',          year: 2015 },
  { stockId: 'ALB-007', vin: '1C4RJFAG0EC000000', make: 'Jeep',      model: 'Grand Cherokee',  year: 2014 }
];
return inventory.map((car) => ({ json: car }));

// vPIC returns { Results: [ {Variable, Value}, ... ] }.
// This is enrichment (body/engine/plant). It degrades gracefully if the VIN
// is unknown — the recall query below always uses the dealer's own
// make/model/year, so a bad VIN never breaks the run.
const src = $('Load dealer inventory').item.json;
const decoded = $json || {};
const results = Array.isArray(decoded.Results) ? decoded.Results : [];

function pick(variable) {
  const row = results.find((r) => r.Variable === variable);
  const v = row ? row.Value : null;
  return v && v !== 'Not Applicable' && v !== '' ? v : null;
}

const decodedMake = pick('Make');

return {
  json: {
    ...src,
    decode: {
      ok: !!decodedMake,
      decodedMake,
      bodyClass: pick('Body Class'),
      engineL: pick('Displacement (L)'),
      plantCountry: pick('Plant Country')
    }
  }
};

// Aggregate every car into ONE report item, and apply idempotency using
// n8n workflow static data so re-runs don't re-alert on the same campaigns.
const recallItems = $input.all();
const carItems = $('Parse VIN decode').all();

const staticData = $getWorkflowStaticData('global');
const alerted = staticData.alertedCampaigns || {};

const flagged = [];
const allCars = [];
let totalOpenRecalls = 0;
let totalNewRecalls = 0;
let cleanCount = 0;

for (let i = 0; i < recallItems.length; i++) {
  const car = carItems[i] ? carItems[i].json : {};
  const resp = recallItems[i] ? recallItems[i].json : {};
  const list = Array.isArray(resp.results) ? resp.results : [];

  const recalls = list.map((r) => ({
    campaign: r.NHTSACampaignNumber || null,
    component: r.Component || 'Unknown',
    summary: r.Summary || '',
    consequence: r.Consequence || '',
    remedy: r.Remedy || '',
    date: r.ReportReceivedDate || ''
  }));

  const count = recalls.length;
  totalOpenRecalls += count;
  if (count === 0) cleanCount++;

  const key = car.stockId || car.vin || String(i);
  const seen = alerted[key] || [];
  const newRecalls = recalls.filter((r) => r.campaign && !seen.includes(r.campaign));
  totalNewRecalls += newRecalls.length;

  const record = {
    stockId: car.stockId,
    vin: car.vin,
    make: car.make,
    model: car.model,
    year: car.year,
    bodyClass: car.decode ? car.decode.bodyClass : null,
    recallCount: count,
    newRecallCount: newRecalls.length,
    recalls,
    newRecalls
  };
  allCars.push(record);
  if (newRecalls.length > 0) flagged.push(record);

  alerted[key] = Array.from(new Set([...seen, ...recalls.map((r) => r.campaign).filter(Boolean)]));
}

staticData.alertedCampaigns = alerted;

const generatedAt = $now.toISO();

const lines = flagged.map((c) => {
  const rl = c.newRecalls
    .map((r) => `   - [${r.campaign}] ${r.component}: ${String(r.summary).slice(0, 220)}`)
    .join('\n');
  return `- ${c.year} ${c.make} ${c.model} (stock ${c.stockId}, VIN ${c.vin}) — ${c.newRecallCount} open recall(s):\n${rl}`;
}).join('\n\n');

const llmPrompt = `Here is today's open-recall scan of a used-car dealership's inventory. Write a concise morning briefing for the sales team (max ~180 words). For each affected car give a one-line plain-English risk and what to tell a prospective buyer. Be factual and calm — no fear-mongering.\n\nScan date: ${generatedAt}\nCars scanned: ${recallItems.length} | Flagged (new recalls): ${flagged.length} | Clean: ${cleanCount}\n\n${lines}`;

const report = {
  generatedAt,
  totalCars: recallItems.length,
  carsFlagged: flagged.length,
  cleanCount,
  totalOpenRecalls,
  totalNewRecalls,
  flagged,
  allCars,
  llmPrompt
};

return [{ json: report }];

// Build the Slack digest text from the LLM briefing + structured fallback.
const report = $('Compile recall report').first().json;
const llm = $json || {};

let briefing = '';
try {
  briefing = llm.content && llm.content[0] && llm.content[0].text ? llm.content[0].text : '';
} catch (e) {
  briefing = '';
}
if (!briefing) briefing = '(LLM briefing unavailable — see the structured list below.)';

const flaggedLines = report.flagged
  .map((c) => `• *${c.year} ${c.make} ${c.model}* (stock ${c.stockId}) — ${c.newRecallCount} open recall(s)`)
  .join('\n');

const text = `:car: *AlbaCars — Daily Recall & Safety Watch*\n` +
  `${report.totalCars} cars scanned · *${report.carsFlagged} flagged* · ${report.cleanCount} clean · ${String(report.generatedAt).slice(0, 10)}\n\n` +
  `${briefing}\n\n*Affected inventory:*\n${flaggedLines}`;

return [{ json: { slackText: text } }];

// No new recalls today — post a short all-clear.
const report = $('Compile recall report').first().json;
const text = `:white_check_mark: *AlbaCars — Daily Recall & Safety Watch*\n` +
  `${report.totalCars} cars scanned · no *new* open recalls today · ${String(report.generatedAt).slice(0, 10)}.\n` +
  `(${report.totalOpenRecalls} previously-known recall(s) already on file.)`;
return [{ json: { slackText: text } }];
